import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testToString() {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        String result = csvFormat.toString();

        // Then
        assertEquals("Delimiter=<,> QuoteChar=<\"> RecordSeparator=<\r\n> EmptyLines:ignored SurroundingSpaces:ignored IgnoreHeaderCase:ignored SkipHeaderRecord:false", result);
    }
}
